tool_calls.call:
cat > /tmp/test_overflow.c << 'EOF'
#include <stdio.h>
#include <string.h>

int main() {
    char buf[256];
    printf("Buffer size: %zu bytes\n", sizeof(buf));
    printf("Input string length: 600 characters + 1 null = 601 bytes\n");
    printf("Overflow: %d bytes\n", 601 - 256);
    return 0;
}
EOF
gcc /tmp/test_overflow.c -o /tmp/test_overflow && /tmp/test_overflow
